using RegistrarManagement.Helpers;using RegistrarManagement.Models;using RegistrarManagement.Services;namespace RegistrarManagement.Forms;public partial class StudentClearancesForm:Form{private readonly ClearanceService _service=new();private readonly StudentService _students=new();private string? _id;public StudentClearancesForm(){InitializeComponent();Load+=Form_Load;cmbRegistrarStatus.Items.AddRange(["Cleared","Pending"]);cmbAccountingStatus.Items.AddRange(["Cleared","Pending"]);cmbGuidanceStatus.Items.AddRange(["Cleared","Pending"]);}private async void Form_Load(object? s,EventArgs e){cmbStudent.DataSource=await _students.GetAllAsync();cmbStudent.DisplayMember="FullName";await LoadGrid();}private async void btnCheckStatus_Click(object? s,EventArgs e){if(cmbStudent.SelectedItem is not Student st)return;txtLibraryStatus.Text=(await _service.GetLibraryAsync(st.StudentId))?.LibraryStatus??"Pending";txtMedicalStatus.Text=(await _service.GetMedicalAsync(st.StudentId))?.MedicalStatus??"Pending";txtOverallStatus.Text=ClearanceService.Overall(Build(_id??""));}private StudentClearance Build(string id){var x=new StudentClearance{ClearanceId=id,StudentId=(cmbStudent.SelectedItem as Student)?.StudentId??"",LibraryStatus=txtLibraryStatus.Text,MedicalStatus=txtMedicalStatus.Text,RegistrarStatus=cmbRegistrarStatus.Text,AccountingStatus=cmbAccountingStatus.Text,GuidanceStatus=cmbGuidanceStatus.Text,Remarks=txtRemarks.Text.Trim(),UpdatedAt=DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss")};x.OverallStatus=ClearanceService.Overall(x);txtOverallStatus.Text=x.OverallStatus;return x;}private async void btnAdd_Click(object? s,EventArgs e){if(cmbStudent.SelectedItem is not Student st)return;if((await _service.GetAllAsync()).Any(x=>x.StudentId==st.StudentId)){MessageBox.Show("Clearance record already exists.");return;}await _service.SaveAsync(Build(IdGenerator.Create("CLR")));await LoadGrid();Clear();}private async void btnUpdate_Click(object? s,EventArgs e){if(_id==null)return;await _service.SaveAsync(Build(_id));await LoadGrid();}private async void btnDelete_Click(object? s,EventArgs e){if(_id!=null&&MessageBox.Show("Delete?","Confirm",MessageBoxButtons.YesNo)==DialogResult.Yes){await _service.DeleteAsync(_id);await LoadGrid();Clear();}}private void btnClear_Click(object? s,EventArgs e)=>Clear();private async void btnRefresh_Click(object? s,EventArgs e)=>await LoadGrid();private async void btnSearch_Click(object? s,EventArgs e){string t=txtSearch.Text.ToLowerInvariant();dgvClearances.DataSource=(await _service.GetAllAsync()).Where(x=>x.ClearanceId.ToLowerInvariant().Contains(t)||x.StudentId.ToLowerInvariant().Contains(t)).ToList();}private async Task LoadGrid()=>dgvClearances.DataSource=await _service.GetAllAsync();private void dgvClearances_CellClick(object? s,DataGridViewCellEventArgs e){if(e.RowIndex<0||dgvClearances.Rows[e.RowIndex].DataBoundItem is not StudentClearance x)return;_id=x.ClearanceId;txtLibraryStatus.Text=x.LibraryStatus;txtMedicalStatus.Text=x.MedicalStatus;cmbRegistrarStatus.Text=x.RegistrarStatus;cmbAccountingStatus.Text=x.AccountingStatus;cmbGuidanceStatus.Text=x.GuidanceStatus;txtOverallStatus.Text=x.OverallStatus;txtRemarks.Text=x.Remarks;SelectStudent(x.StudentId);btnUpdate.Enabled=btnDelete.Enabled=true;}private void SelectStudent(string id){for(int i=0;i<cmbStudent.Items.Count;i++)if((cmbStudent.Items[i] as Student)?.StudentId==id){cmbStudent.SelectedIndex=i;break;}}private void Clear(){_id=null;txtLibraryStatus.Clear();txtMedicalStatus.Clear();txtOverallStatus.Clear();txtRemarks.Clear();cmbRegistrarStatus.SelectedIndex=cmbAccountingStatus.SelectedIndex=cmbGuidanceStatus.SelectedIndex=-1;btnUpdate.Enabled=btnDelete.Enabled=false;}}
